 using System.ComponentModel;
 using System.Net;
 using System.Text;
 using System.Text.RegularExpressions;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration ---
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable.");
 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

 // --- Tools ---
 var notebook = new Notebook();
 using var httpClient = new HttpClient();
 httpClient.DefaultRequestHeaders.UserAgent.ParseAdd(
     "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
 httpClient.Timeout = TimeSpan.FromSeconds(15);

 // --- Build AI client with automatic function invocation ---
 IChatClient client = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient()
     .AsBuilder()
     .UseFunctionInvocation()
     .Build();

 // --- Get research topic ---
 var topic = args.Length > 0
     ? string.Join(' ', args)
     : PromptForTopic();

 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 // --- Define tools ---
 var chatOptions = new ChatOptions
 {
     Tools =
     [
         AIFunctionFactory.Create(SearchWeb,
             "SearchWeb",
             "Search the web for information on a query. Returns up to 5 result snippets."),
         AIFunctionFactory.Create(notebook.TakeNote,
             "TakeNote",
             "Save a research note for later reference. Use this to record key findings."),
         AIFunctionFactory.Create(notebook.ReadNotes,
             "ReadNotes",
             "Read all previously saved research notes."),
     ]
 };

 // --- Conversation setup ---
 List<ChatMessage> messages =
 [
     new(ChatRole.System, """
         You are a thorough research agent. Your goal is to investigate a topic using
         the tools at your disposal and then produce a well-organized summary.

         Process:
         1. Run 2–3 web searches with varied queries to cover different angles.
         2. After each search, call TakeNote to record the most important facts.
         3. When you have gathered enough material, call ReadNotes to review everything.
         4. Write a comprehensive, well-structured summary with clear sections.

         Guidelines:
         - Vary your search queries (e.g., overview, recent developments, key people).
         - Always take notes before moving to the next search.
         - Include specific facts, dates, and figures in your summary.
         """),
     new(ChatRole.User,
         $"Please research the following topic and provide a comprehensive summary:\n\n{topic}")
 ];

 // --- Run the agent loop ---
 Console.WriteLine("Agent is working…\n");
 var response = await client.GetResponseAsync(messages, chatOptions);

 Console.WriteLine();
 Console.WriteLine("══════════════════════════════════════════");
 Console.WriteLine("            RESEARCH SUMMARY");
 Console.WriteLine("══════════════════════════════════════════");
 Console.WriteLine();
 Console.WriteLine(response.Text);

 if (notebook.Notes.Count > 0)
 {
     Console.WriteLine();
     Console.WriteLine("══════════════════════════════════════════");
     Console.WriteLine($"         RESEARCH NOTES ({notebook.Notes.Count})");
     Console.WriteLine("══════════════════════════════════════════");
     Console.WriteLine();
     for (var i = 0; i < notebook.Notes.Count; i++)
         Console.WriteLine($"[{i + 1}] {notebook.Notes[i]}\n");
 }

