 static string? PromptForTopic()
 {
     Console.Write("Enter a research topic: ");
     return Console.ReadLine()?.Trim();
 }

 async Task<string> SearchWeb(
     [Description("The search query string")] string query)
 {
     Console.WriteLine($"  🌐 Searching: \"{query}\"");
     try
     {
         var encoded = WebUtility.UrlEncode(query);
         var url = $"https://html.duckduckgo.com/html/?q={encoded}";
         var html = await httpClient.GetStringAsync(url);

         var results = ParseSearchResults(html);

         if (results.Count == 0)
             return "No results found for this query. Try different wording.";

         return string.Join("\n\n", results);
     }
     catch (Exception ex)
     {
         return $"Search failed: {ex.Message}. Try a different query.";
     }
 }

 static List<string> ParseSearchResults(string html)
 {
     var results = new List<string>();

     // Match each result block: title inside <a class="result__a"> and
     // snippet inside <a class="result__snippet">
     var pattern = SearchRegexes.ResultBlockRegex();

     foreach (Match match in pattern.Matches(html))
     {
         if (results.Count >= 5) break;

         var title = StripHtml(match.Groups["title"].Value).Trim();
         var snippet = StripHtml(match.Groups["snippet"].Value).Trim();

         if (!string.IsNullOrEmpty(title) && !string.IsNullOrEmpty(snippet))
             results.Add($"• {title}\n  {snippet}");
     }

     return results;
 }

 static string StripHtml(string html)
 {
     var text = SearchRegexes.HtmlTagRegex().Replace(html, "");
     return text
         .Replace("&amp;", "&")
         .Replace("&lt;", "<")
         .Replace("&gt;", ">")
         .Replace("&quot;", "\"")
         .Replace("&#x27;", "'")
         .Replace("&nbsp;", " ");
 }

