 class Notebook
 {
     public List<string> Notes { get; } = [];

     public string TakeNote(
         [Description("The content of the research note to save")] string note)
     {
         Notes.Add(note);
         Console.WriteLine($"  📝 Note saved ({Notes.Count} total)");
         return $"Note saved successfully. You now have {Notes.Count} note(s).";
     }

     public string ReadNotes()
     {
         Console.WriteLine($"  📖 Reading {Notes.Count} note(s)");
         if (Notes.Count == 0)
             return "No notes taken yet.";

         var sb = new StringBuilder();
         for (var i = 0; i < Notes.Count; i++)
         {
             sb.AppendLine($"Note {i + 1}:");
             sb.AppendLine(Notes[i]);
             sb.AppendLine();
         }
         return sb.ToString();
     }
 }
